/* BTHoverCard — floating hover card.
   Figma node 2065-2405 · D - HoverCard
   Web only. Single CSS file — copied verbatim to both vue/ and react/ folders.
   All colors via @btech/tokens CSS vars — no hex fallbacks. */

/* ── Trigger wrapper ─────────────────────────────────────────── */
/* display:contents makes the span layout-transparent — it does not
   create its own box. Event bubbling still works normally. */
.bt-hover-card-trigger {
  display: contents;
}

/* ── Content panel ───────────────────────────────────────────── */
.bt-hover-card-content {
  position: fixed;
  z-index: 50;
  width: fit-content;
  max-width: 380px;
  box-sizing: border-box;
  background: var(--bg-primary);
  border: 1px solid var(--border-primary);
  border-radius: var(--radius-md);
  padding: var(--space-lg);
  box-shadow: var(--shadow-elevation-xl);
  outline: none;
  /* Hidden until JS positions and reveals the panel */
  opacity: 0;
}

.bt-hover-card-content--visible {
  animation: bt-hover-card-in 120ms ease-out forwards;
}

@keyframes bt-hover-card-in {
  from { opacity: 0; transform: scale(0.97); }
  to   { opacity: 1; transform: scale(1); }
}

/* ── BTHoverCardItem ─────────────────────────────────────────── */
.bt-hover-card-item {
  display: flex;
  flex-direction: column;
  gap: var(--space-sm);
}

.bt-hover-card-item__title {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 700;
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
  color: var(--text-primary);
  margin: 0;
}

.bt-hover-card-item__description {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
  color: var(--text-primary);
  margin: 0;
}

.bt-hover-card-item__caption {
  font-family: var(--typography-font-family-sans);
  font-size: var(--typography-font-size-2xs);
  font-weight: 500;
  line-height: var(--typography-line-height-xs);
  letter-spacing: 0;
  color: var(--text-secondary);
  margin: 0;
}

/**
 * BTHoverCard — root component (React).
 *
 * Manages open state and delay timers. Distributes shared context to
 * BTHoverCardTrigger and BTHoverCardContent via React Context.
 *
 * Hover lifecycle:
 *   mouseenter trigger → openDelay timer → isOpen = true
 *   mouseleave trigger → closeDelay timer (cancelled if mouse enters content)
 *   mouseleave content → closeDelay timer → isOpen = false
 *   Escape key         → close immediately
 *
 * @example
 * <BTHoverCard>
 *   <BTHoverCardTrigger>
 *     <BTButton label="Hover me" />
 *   </BTHoverCardTrigger>
 *   <BTHoverCardContent side="bottom" align="center">
 *     <BTHoverCardItem title="Title" description="..." caption="..." />
 *   </BTHoverCardContent>
 * </BTHoverCard>
 */
import { createContext, useContext, useRef, useState, useCallback } from 'react';
import type { BTHoverCardProps } from './BTHoverCard.types';

// ── Context ──────────────────────────────────────────────────────────────────

export interface BTHoverCardContextValue {
  isOpen:        boolean;
  triggerRef:    React.MutableRefObject<HTMLElement | null>;
  scheduleOpen:  () => void;
  scheduleClose: () => void;
  cancelClose:   () => void;
  /** Close immediately — used by Escape key for accessibility. */
  close:         () => void;
}

export const BTHoverCardContext = createContext<BTHoverCardContextValue | null>(null);

export function useBTHoverCardContext(): BTHoverCardContextValue {
  const ctx = useContext(BTHoverCardContext);
  if (!ctx) throw new Error('BTHoverCardTrigger / BTHoverCardContent must be inside <BTHoverCard>.');
  return ctx;
}

// ── Component ────────────────────────────────────────────────────────────────

export function BTHoverCard({
  openDelay  = 0,
  closeDelay = 0,
  children,
}: BTHoverCardProps) {
  const [isOpen, setIsOpen] = useState(false);
  const triggerRef = useRef<HTMLElement | null>(null);

  // Use refs for timers so their IDs are always current in callbacks without
  // causing stale-closure issues (no re-render needed to update timer ref).
  const openTimerRef  = useRef<ReturnType<typeof setTimeout> | null>(null);
  const closeTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const scheduleOpen = useCallback(() => {
    if (closeTimerRef.current) { clearTimeout(closeTimerRef.current); closeTimerRef.current = null; }
    if (isOpen) return;
    openTimerRef.current = setTimeout(() => { setIsOpen(true); }, openDelay);
  }, [isOpen, openDelay]);

  const scheduleClose = useCallback(() => {
    if (openTimerRef.current) { clearTimeout(openTimerRef.current); openTimerRef.current = null; }
    closeTimerRef.current = setTimeout(() => { setIsOpen(false); }, closeDelay);
  }, [closeDelay]);

  const cancelClose = useCallback(() => {
    if (closeTimerRef.current) { clearTimeout(closeTimerRef.current); closeTimerRef.current = null; }
  }, []);

  const close = useCallback(() => {
    if (openTimerRef.current)  { clearTimeout(openTimerRef.current);  openTimerRef.current  = null; }
    if (closeTimerRef.current) { clearTimeout(closeTimerRef.current); closeTimerRef.current = null; }
    setIsOpen(false);
  }, []);

  return (
    <BTHoverCardContext.Provider value={{ isOpen, triggerRef, scheduleOpen, scheduleClose, cancelClose, close }}>
      {children}
    </BTHoverCardContext.Provider>
  );
}

BTHoverCard.displayName = 'BTHoverCard';

/**
 * BTHoverCard — public prop types (React).
 * Figma node 2065-2405 · D - HoverCard
 * Web only (Vue 3 + React 18). No Flutter.
 */

export type BTHoverCardSide  = 'top' | 'bottom' | 'left' | 'right';
export type BTHoverCardAlign = 'start' | 'center' | 'end';

export interface BTHoverCardProps {
  /** Delay in ms before the card opens after mouseenter. Default: 0. */
  openDelay?:  number;
  /** Delay in ms before the card closes after mouseleave. Default: 0. */
  closeDelay?: number;
  children?:   React.ReactNode;
}

export interface BTHoverCardTriggerProps {
  // no public props — wraps children transparently
  children?: React.ReactNode;
}

export interface BTHoverCardContentProps {
  /** Which side of the trigger to render the panel on. Default: 'bottom'. */
  side?:       BTHoverCardSide;
  /** Alignment of the panel relative to the trigger. Default: 'center'. */
  align?:      BTHoverCardAlign;
  /** Gap in px between trigger edge and panel edge. Default: 8. */
  sideOffset?: number;
  children?:   React.ReactNode;
}

export interface BTHoverCardItemProps {
  /** Bold title text — always shown. */
  title:        string;
  /** Optional secondary line — 14px, text-primary. */
  description?: string;
  /** Optional tertiary line — 10px, text-secondary. */
  caption?:     string;
}

/**
 * BTHoverCardContent — the floating card panel (React).
 *
 * Portal-rendered via createPortal to escape overflow:hidden ancestors.
 * Positioning is done inline (positionPopover algorithm) since React has no
 * shared utils folder — same logic as positionFloating.ts in the Vue package.
 *
 * mouseenter → cancel the close timer (hover bridge: user moved from trigger to card).
 * mouseleave → restart the close timer.
 * Escape key → close immediately (accessibility).
 *
 * @example
 * <BTHoverCardContent side="bottom" align="center" sideOffset={8}>
 *   <BTHoverCardItem title="Title" description="Desc" caption="Caption" />
 * </BTHoverCardContent>
 */
import './BTHoverCard.css';
import { useEffect, useRef, useCallback, type ReactNode } from 'react';
import { createPortal } from 'react-dom';
import { useBTHoverCardContext } from './BTHoverCard';
import type { BTHoverCardContentProps } from './BTHoverCard.types';

// ── Inline positionPopover (mirrors positionFloating.ts from the Vue package) ──

type Side  = 'top' | 'bottom' | 'left' | 'right';
type Align = 'start' | 'center' | 'end';

function positionPopover(
  trigger: HTMLElement,
  panel:   HTMLElement,
  opts: { side?: Side; align?: Align; sideOffset?: number; margin?: number } = {},
): void {
  const { side = 'bottom', align = 'start', sideOffset = 8, margin = 8 } = opts;
  const tRect = trigger.getBoundingClientRect();
  const pRect = panel.getBoundingClientRect();
  const vw = window.innerWidth;
  const vh = window.innerHeight;

  // ── Resolve side with auto-flip ───────────────────────────────────────────
  let resolvedSide = side;
  if (side === 'bottom') {
    const fits = vh - tRect.bottom - sideOffset >= pRect.height;
    if (!fits && tRect.top - sideOffset >= pRect.height) resolvedSide = 'top';
  } else if (side === 'top') {
    const fits = tRect.top - sideOffset >= pRect.height;
    if (!fits && vh - tRect.bottom - sideOffset >= pRect.height) resolvedSide = 'bottom';
  } else if (side === 'right') {
    const fits = vw - tRect.right - sideOffset >= pRect.width;
    if (!fits && tRect.left - sideOffset >= pRect.width) resolvedSide = 'left';
  } else /* left */ {
    const fits = tRect.left - sideOffset >= pRect.width;
    if (!fits && vw - tRect.right - sideOffset >= pRect.width) resolvedSide = 'right';
  }

  // ── Main axis ─────────────────────────────────────────────────────────────
  let top  = 0;
  let left = 0;
  if      (resolvedSide === 'bottom') top  = tRect.bottom + sideOffset;
  else if (resolvedSide === 'top')    top  = tRect.top - pRect.height - sideOffset;
  else if (resolvedSide === 'right')  left = tRect.right  + sideOffset;
  else /* left */                     left = tRect.left  - pRect.width - sideOffset;

  // ── Cross axis (alignment) ────────────────────────────────────────────────
  if (resolvedSide === 'top' || resolvedSide === 'bottom') {
    if      (align === 'start')  left = tRect.left;
    else if (align === 'center') left = tRect.left + tRect.width / 2 - pRect.width / 2;
    else /* end */               left = tRect.right - pRect.width;

    // Clamp horizontally
    left = Math.min(left, vw - margin - pRect.width);
    left = Math.max(left, margin);
  } else {
    if      (align === 'start')  top = tRect.top;
    else if (align === 'center') top = tRect.top + tRect.height / 2 - pRect.height / 2;
    else /* end */               top = tRect.bottom - pRect.height;

    // Clamp vertically
    top = Math.min(top, vh - margin - pRect.height);
    top = Math.max(top, margin);
  }

  panel.style.top  = `${Math.round(top)}px`;
  panel.style.left = `${Math.round(left)}px`;
}

// ── Component ────────────────────────────────────────────────────────────────

export function BTHoverCardContent({
  side       = 'bottom',
  align      = 'center',
  sideOffset = 8,
  children,
}: BTHoverCardContentProps & { children?: ReactNode }) {
  const ctx        = useBTHoverCardContext();
  const contentRef = useRef<HTMLDivElement>(null);

  // ── Positioning ────────────────────────────────────────────────────────────
  const updatePosition = useCallback(() => {
    const wrapper = ctx.triggerRef.current;
    const content = contentRef.current;
    if (!wrapper || !content) return;

    // display:contents span → measure its first child (the actual trigger).
    const trigger =
      getComputedStyle(wrapper).display === 'contents'
        ? ((wrapper.firstElementChild as HTMLElement) ?? wrapper)
        : wrapper;

    positionPopover(trigger, content, { side, align, sideOffset, margin: 8 });

    // Reveal panel with entrance animation.
    content.classList.add('bt-hover-card-content--visible');
  }, [side, align, sideOffset]);

  // Scroll + resize reposition
  useEffect(() => {
    if (!ctx.isOpen) return;

    // rAF ensures the portal is painted before we measure its dimensions.
    const raf = requestAnimationFrame(updatePosition);

    const onScroll = () => updatePosition();
    const onResize = () => updatePosition();

    document.addEventListener('scroll', onScroll, true);
    window.addEventListener  ('resize', onResize);

    return () => {
      cancelAnimationFrame(raf);
      document.removeEventListener('scroll', onScroll, true);
      window.removeEventListener  ('resize', onResize);
    };
  }, [ctx.isOpen, updatePosition]);

  // Escape key — close immediately (accessibility)
  useEffect(() => {
    if (!ctx.isOpen) return;

    function onKeyDown(e: KeyboardEvent) {
      if (e.key === 'Escape') ctx.close();
    }

    document.addEventListener('keydown', onKeyDown);
    return () => document.removeEventListener('keydown', onKeyDown);
  }, [ctx.isOpen, ctx]);

  // ── Render ─────────────────────────────────────────────────────────────────
  if (!ctx.isOpen) return null;

  return createPortal(
    <div
      ref={contentRef}
      className="bt-hover-card-content"
      role="dialog"
      tabIndex={-1}
      onMouseEnter={ctx.cancelClose}
      onMouseLeave={ctx.scheduleClose}
    >
      {children}
    </div>,
    document.body,
  );
}

BTHoverCardContent.displayName = 'BTHoverCardContent';

/**
 * BTHoverCardItem — canonical Figma content layout (React).
 *
 * Purely presentational: title (bold 14px) + optional description (14px) +
 * optional caption (10px secondary). Callers may render any arbitrary content
 * inside BTHoverCardContent instead of using BTHoverCardItem.
 *
 * @example
 * <BTHoverCardItem
 *   title="BTech Design System"
 *   description="Component library for Vue, React & Flutter."
 *   caption="Joined May 2026"
 * />
 */
import type { BTHoverCardItemProps } from './BTHoverCard.types';

export function BTHoverCardItem({ title, description, caption }: BTHoverCardItemProps) {
  return (
    <div className="bt-hover-card-item">
      <p className="bt-hover-card-item__title">{title}</p>
      {description && <p className="bt-hover-card-item__description">{description}</p>}
      {caption     && <p className="bt-hover-card-item__caption">{caption}</p>}
    </div>
  );
}

BTHoverCardItem.displayName = 'BTHoverCardItem';

/**
 * BTHoverCardTrigger — hover wrapper (React).
 *
 * Wraps its children in a layout-transparent <span> (display: contents).
 * Registers itself as the trigger element so BTHoverCardContent knows where
 * to position the floating panel.
 *
 * Listens to onMouseEnter / onMouseLeave and delegates to context timers.
 *
 * @example
 * <BTHoverCardTrigger>
 *   <BTButton label="Hover me" />
 * </BTHoverCardTrigger>
 */
import type { ReactNode } from 'react';
import { useBTHoverCardContext } from './BTHoverCard';

interface BTHoverCardTriggerProps {
  children?: ReactNode;
}

export function BTHoverCardTrigger({ children }: BTHoverCardTriggerProps) {
  const ctx = useBTHoverCardContext();

  return (
    <span
      ref={ctx.triggerRef as React.MutableRefObject<HTMLSpanElement | null>}
      className="bt-hover-card-trigger"
      onMouseEnter={ctx.scheduleOpen}
      onMouseLeave={ctx.scheduleClose}
    >
      {children}
    </span>
  );
}

BTHoverCardTrigger.displayName = 'BTHoverCardTrigger';
